```ts
// used from https://stackoverflow.com/a/25490531
const getCookieValue = (name: string): string =>
  document.cookie.match('(^|;)\\s*' + name + '\\s*=\\s*([^;]+)')?.pop() || '';

export function addXsrfHeader(axiosInstance: AxiosInstance): void {
  axiosInstance.interceptors.request.use((config: InternalAxiosRequestConfig) => {
    const xsrfCookie = getCookieValue('XSRF-TOKEN');

    if (config.method === 'GET' || config.method === 'HEAD') {
      return config;
    }

    if (xsrfCookie !== '') {
      config.headers.set('X-XSRF-TOKEN', decodeURIComponent(xsrfCookie));
    }

    return config;
  });
}
```

